def api_response_cache(ttl=API_CACHE_TTL):
    def decorator(f):
        @wraps(f)
        def wrapper(*args, **kwargs):
            request_fingerprint = json.dumps(
                {
                    "path": request.path,
                    "args": sorted(request.args.items()),
                    "method": request.method,
                },
                sort_keys=True,
            )
            key = cache_key("api", request_fingerprint)
            cached = memcache_get_json(key)
            if cached is not None:
                return jsonify({"source": "cache", "cached_at": cached.get("cached_at"), "data": cached.get("data")})

            response_data = f(*args, **kwargs)
            payload = {
                "cached_at": int(time.time()),
                "data": response_data,
            }
            memcache_set_json(key, payload, ttl)
            return jsonify({"source": "origin", **payload})

        return wrapper

    return decorator


def fetch_users_from_db(limit=None):
    query = "SELECT id, name, email FROM users ORDER BY id"
    params = []
    if limit is not None:
        query += " LIMIT ?"
        params.append(limit)

    query_signature = json.dumps({"query": query, "params": params}, sort_keys=True)
    key = cache_key("dbquery", query_signature)
    cached = memcache_get_json(key)
    if cached is not None:
        return {"source": "cache", "rows": cached}

    conn = get_db_connection()
    cur = conn.cursor()
    cur.execute(query, params)
    rows = [dict(row) for row in cur.fetchall()]
    conn.close()

    memcache_set_json(key, rows, QUERY_CACHE_TTL)
    return {"source": "database", "rows": rows}


def fetch_user_by_id_from_db(user_id):
    query = "SELECT id, name, email FROM users WHERE id = ?"
    params = [user_id]
    query_signature = json.dumps({"query": query, "params": params}, sort_keys=True)
    key = cache_key("dbquery", query_signature)
    cached = memcache_get_json(key)
    if cached is not None:
        return {"source": "cache", "row": cached}

    conn = get_db_connection()
    cur = conn.cursor()
    cur.execute(query, params)
    row = cur.fetchone()
    conn.close()

    result = dict(row) if row else None
    memcache_set_json(key, result, QUERY_CACHE_TTL)
    return {"source": "database", "row": result}


@app.route("/health", methods=["GET"])
def health():
    memcached_status = "unavailable"
    try:
        memcache.set("healthcheck", "ok", expire=5)
        val = memcache.get("healthcheck")
        if isinstance(val, bytes):
            val = val.decode("utf-8")
        if val == "ok":
            memcached_status = "ok"
    except Exception:
        memcached_status = "unavailable"

    return jsonify(
        {
            "status": "ok",
            "memcached": memcached_status,
            "database": "ok",
        }
    )


