@app.route("/users", methods=["POST"])
def create_user():
    data = request.get_json(silent=True) or {}
    name = data.get("name")
    email = data.get("email")

    if not name or not email:
        return jsonify({"error": "Both name and email are required"}), 400

    try:
        conn = get_db_connection()
        cur = conn.cursor()
        cur.execute("INSERT INTO users (name, email) VALUES (?, ?)", (name, email))
        user_id = cur.lastrowid
        conn.commit()
        conn.close()
    except sqlite3.IntegrityError:
        return jsonify({"error": "Email already exists"}), 409

    memcache_delete(cache_key("api", json.dumps({"path": "/stats", "args": [], "method": "GET"}, sort_keys=True)))
    return jsonify({"id": user_id, "name": name, "email": email}), 201


@app.route("/stats", methods=["GET"])
@api_response_cache(ttl=API_CACHE_TTL)
def stats():
    conn = get_db_connection()
    cur = conn.cursor()
    cur.execute("SELECT COUNT(*) AS total_users FROM users")
    total_users = cur.fetchone()["total_users"]
    conn.close()

    return {
        "total_users": total_users,
        "generated_at": int(time.time()),
        "api_cache_ttl_seconds": API_CACHE_TTL,
    }


@app.route("/cache/invalidate", methods=["POST"])
def invalidate_cache():
    payload = request.get_json(silent=True) or {}
    key = payload.get("key")
    if not key:
        return jsonify({"error": "key is required"}), 400
    memcache_delete(key)
    return jsonify({"message": "cache invalidated", "key": key})


